        /// key, if they have been set.
        /// 
        /// Fails with `header-error.immutable` if the `fields` are immutable.
        std::expected<void, HeaderError> Set(std::string_view name, std::span<std::span<uint8_t const> const> value) const;
        /// Delete all values for a key. Does nothing if no values for the key
        /// exist.
        /// 
        /// Fails with `header-error.immutable` if the `fields` are immutable.
        std::expected<void, HeaderError> Delete(std::string_view name) const;
        /// Append a value for a key. Does not change or delete any existing
        /// values for that key.
        /// 
        /// Fails with `header-error.immutable` if the `fields` are immutable.
        std::expected<void, HeaderError> Append(std::string_view name, std::span<uint8_t const> value) const;
